        const text = String(value || '').trim();
        if (!text || !/[가-힣]/.test(text)) return '';
        if (romanizeCache.has(text)) return romanizeCache.get(text);

        const CHO = ['g', 'kk', 'n', 'd', 'tt', 'r', 'm', 'b', 'pp', 's', 'ss', '', 'j', 'jj', 'ch', 'k', 't', 'p', 'h'];
        const JUNG = ['a', 'ae', 'ya', 'yae', 'eo', 'e', 'yeo', 'ye', 'o', 'wa', 'wae', 'oe', 'yo', 'u', 'wo', 'we', 'wi', 'yu', 'eu', 'ui', 'i'];
        const JONG = ['', 'k', 'k', 'ks', 'n', 'nj', 'nh', 't', 'l', 'lk', 'lm', 'lb', 'ls', 'lt', 'lp', 'lh', 'm', 'p', 'ps', 't', 't', 'ng', 't', 't', 'k', 't', 'p', 'h'];
        let out = '';
        for (const ch of text) {
            const code = ch.charCodeAt(0);
            if (code < 0xac00 || code > 0xd7a3) {
                out += ch.toLowerCase();
                continue;
            }
            const syllableIndex = code - 0xac00;
            const cho = Math.floor(syllableIndex / 588);
            const jung = Math.floor((syllableIndex % 588) / 28);
            const jong = syllableIndex % 28;
            out += `${CHO[cho]}${JUNG[jung]}${JONG[jong]}`;
        }
        const result = normalizeIdentityToken(out);
        if (romanizeCache.size > 1000) romanizeCache.clear();
        romanizeCache.set(text, result);
        return result;
