                ki: hasNegation(/(?:기공|내공|qi|ki|cultivation).{0,12}(?:아니|없|x|아님|not|no)/i) || hasNegation(/(?:아니|없|x|아님|not|no).{0,12}(?:기공|내공|qi|ki|cultivation)/i),
